function categorizeEmail(email) {
  const lower = email.toLowerCase();

  const genericPatterns = [
    'info@', 'kontakt@', 'contact@', 'hello@', 'mail@', 
    'office@', 'service@', 'support@', 'sales@', 'vertrieb@',
    'bewerbung@', 'karriere@', 'jobs@'
  ];

  const ceoPatterns = [
    'geschaeftsfuehrung@', 'gf@', 'ceo@', 'director@',
    'inhaber@', 'owner@', 'vorstand@', 'geschaeftsleitung@',
    'management@', 'leitung@'
  ];

  if (ceoPatterns.some(pattern => lower.includes(pattern))) {
    return { priority: 1, type: 'ceo_functional', email };
  }

  if (genericPatterns.some(pattern => lower.includes(pattern))) {
    return { priority: 3, type: 'generic', email };
  }

  // Personal email pattern: vorname.nachname@ oder v.nachname@
  if (/^[a-z]{1,2}\.[a-z]+@/.test(lower) || /^[a-z]+\.[a-z]+@/.test(lower)) {
    return { priority: 2, type: 'personal', email };
  }

  return { priority: 4, type: 'unknown', email };
}

