  // Email scoring
  if (primaryEmail) {
    if (primaryEmail.type === 'ceo_identified') score += 40;
    else if (primaryEmail.type === 'location_manager') score += 45;
    else if (primaryEmail.type === 'ceo_functional') score += 30;
    else if (primaryEmail.type === 'personal') score += 20;
    else if (primaryEmail.type === 'decision_maker') score += 25;
    else if (primaryEmail.type === 'best_email') score += 20;
    else if (primaryEmail.type === 'generic') score += 10;
    else score += 5;
  }

  if (sourceData.ceo_name || sourceData.target_location?.manager_name) score += 15;
  if (sourceData.phones && sourceData.phones.length > 0) score += 10;
  if (sourceData.address || sourceData.top_location || sourceData.target_location?.address) score += 10;
  if (sourceData.company_name) score += 15;

  if (!perplexityRejected && data._metadata?.domain_verified) score += 10;

  if (dataSource === 'firecrawl_fallback' && sourceData.unique_points?.length > 0) {
    score += 5;
    console.log('   ✅ Quality bonus: Firecrawl content available (+5)');
