  // ✅ SOCIAL MEDIA BONUS
  if (hasSocialMedia.ceo_linkedin || hasSocialMedia.ceo_xing) {
    score += 5;
    console.log('   ✅ Quality bonus: Personal social media (+5)');
  }

  if (hasSocialMedia.company_linkedin || hasSocialMedia.company_facebook) {
    score += 5;
    console.log('   ✅ Quality bonus: Company social media (+5)');
  }

  return Math.max(0, Math.min(score, 100));
}

