// ---------- Helpers ----------
function uniq(arr) {
  return [...new Set((arr || []).filter(Boolean).map(v => String(v).trim()).filter(Boolean))];
}
function norm(s) {
  return (s === null || s === undefined) ? "" : String(s).trim();
}
function toHttp(url) {
  if (!url) return null;
  let u = String(url).trim();
  if (!u) return null;
  if (!/^https?:\/\//i.test(u)) u = "https://" + u;
  return u;
}
function domainFromWebsite(website) {
  if (!website) return null;
  return String(website)
    .replace(/^https?:\/\//i, "")
    .replace(/^www\./i, "")
    .split("/")[0]
    .toLowerCase();
}
function emailDomain(email) {
  const e = norm(email).toLowerCase();
  if (!e.includes("@")) return null;
  return e.split("@")[1] || null;
}

// ---------- Email ----------
function isValidEmail(email) {
  if (!email) return false;
  const str = String(email).trim().toLowerCase();
  if (str.length < 6 || str.length > 254) return false;
  if (["null","undefined","[null]"].includes(str)) return false;
  if (/\.(png|jpg|jpeg|gif|svg|webp|ico|bmp|pdf|doc|docx|xls|xlsx|zip|rar)$/i.test(str)) return false;
  const emailRegex = /^[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}$/i;
  if (!emailRegex.test(str)) return false;
  const blacklist = ["example.com","test.com","domain.com","email.com","yoursite.com","placeholder.com"];
  const dom = str.split("@")[1];
  if (blacklist.includes(dom)) return false;
  return true;
}
function extractCleanEmail(value) {
  if (!value) return null;
  const str = String(value).trim();
  if (isValidEmail(str)) return str.toLowerCase();
  const m = str.match(/[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}/i);
  if (m && isValidEmail(m[0])) return m[0].toLowerCase();
  return null;
}

// ---------- Name ----------
function isValidName(name) {
  const s = norm(name);
  return s.length > 2 && !["null","undefined","[null]"].includes(s);
}
function normLeadType(v) {
  const s = norm(v);
  return s ? s.toLowerCase() : null;
}
function parsePersonName(fullName) {
  if (!fullName || typeof fullName !== "string") {
    return { firstName: "", lastName: "", cleanName: "", titles: [] };
  }
  const original = fullName.trim();
  const titlePattern =
    /^(Dr\.|Prof\.|Dipl\.-[A-Za-zäöüÄÖÜ-]+\.?|Dipl\.|M\.Sc\.|M\.A\.|B\.Sc\.|B\.A\.|MBA|Ph\.?D\.?|Rechtsanwalt|Rechtsanwältin|RA|Steuerberater|Steuerberaterin|Herr|Frau|Mr\.|Mrs\.|Ms\.|Miss)\s+/i;

  let cleaned = original;
  const titles = [];
  let loop = 0;

  while (loop < 10) {
    const m = cleaned.match(titlePattern);
    if (!m) break;
    titles.push(m[1]);
    cleaned = cleaned.replace(titlePattern, "").trim();
    loop++;
  }

  cleaned = cleaned.replace(/\s+/g, " ").trim();
  const parts = cleaned.split(/\s+/).filter(Boolean);

  if (parts.length === 0) return { firstName: "", lastName: "", cleanName: "", titles };
  if (parts.length === 1) return { firstName: "", lastName: parts[0], cleanName: parts[0], titles };

  return {
    firstName: parts[0],
    lastName: parts.slice(1).join(" "),
    cleanName: cleaned,
    originalName: original,
    titles,
  };
}

