const PROVIDER_DOMAIN_HINTS = [
  "iitr.de",
  "e-recht24.de",
  "it-recht-kanzlei.de",
  "datenschutz-generator.de",
  "trustedshops.com",
  "trustedshops.de",
  "dr-dsgvo.de",
  "legaltrust.de",
  "janolaw.de",
  "haendlerbund.de",
];

function scoreEmailForOutreach(email, companyDomain) {
  if (!isValidEmail(email)) return -999;
  const e = String(email).trim().toLowerCase();
  const dom = emailDomain(e) || "";
  let score = 0;

  if (companyDomain && dom === companyDomain) score += 100;
  if (companyDomain && dom === companyDomain) {
    if (/^(info|kontakt|contact|hello|sales|anfrage|office|mail|service|support)@/i.test(e)) score += 20;
  }

  const providerHit = PROVIDER_DOMAIN_HINTS.some(h => dom.includes(h));
  if (providerHit) score -= 80;

  if (companyDomain && dom !== companyDomain) score -= 30;
  return score;
}

function pickBestEmail(candidates, companyDomain) {
  const cleaned = uniq(candidates.map(extractCleanEmail).filter(Boolean)).filter(isValidEmail);
  if (!cleaned.length) return null;
  const scored = cleaned
    .map(e => ({ e, s: scoreEmailForOutreach(e, companyDomain) }))
    .sort((a, b) => b.s - a.s);
  return scored[0]?.e || null;
}

// ---------- Phone utils ----------
function cleanPhone(v) {
  if (!v) return null;
  let s = String(v).trim();

  s = s.replace(/[^\d+]/g, ""); // keep digits and plus

  if (s.startsWith("0049")) s = "+49" + s.slice(4);
  if (/^0\d{6,}$/.test(s)) s = "+49" + s.slice(1);

  const digits = s.replace(/[^\d]/g, "");
  if (digits.length < 10) return null;

  return s;
}

// filter out obvious garbage numbers your crawler produced
function isLikelyRealPhone(p) {
  if (!p) return false;
  const s = String(p).trim();
  const digits = s.replace(/[^\d]/g, "");

  if (digits.length < 10) return false;

  // reject suspicious short +20... garbage (you had tons of these)
  if (s.startsWith("+20") && digits.length <= 12) return false;

  if (s.startsWith("+49")) return true;

  return true;
}

// Prefer mobile first if available (+49 17x...)
function phonePriority(p) {
  if (!p) return 999;
  const s = String(p);
  if (/^\+49(1[567]\d)/.test(s.replace(/[^\d+]/g, ""))) return 1; // mobile-ish
  if (/^\+49/.test(s)) return 2;
  return 5;
}

