function domain(u){
  try { return new URL(u).hostname.replace(/^www\./,''); }
  catch(e) { return ''; }
}

function domainNameFromUrl(u){
  const d = domain(u);
  if(!d) return null;
  return d.split('.').slice(0,-1).join(' ')
          .split(/[-_]/).map(w=>w.charAt(0).toUpperCase()+w.slice(1)).join(' ');
}

function generateStableId(website) {
  if (!website) return null;
  try {
    let normalized = String(website)
      .toLowerCase()
      .trim()
      .replace(/^https?:\/\//, '')
      .replace(/^www\./, '')
      .replace(/\/$/, '')
      .split('/')[0]
      .split('?')[0]
      .split('#')[0];
    return normalized;
  } catch (e) {
    return String(website).toLowerCase().replace(/[^a-z0-9.-]/g, '');
  }
}

function detectCategory(searchQuery, services, companyName, topService, leadType){
  if (leadType) {
    const lt = String(leadType).toLowerCase();
    if (lt === 'investor') return 'Investor';
    if (lt === 'saas') return 'SaaS';
    if (lt === 'agency') return 'Agentur';
    if (lt === 'ecommerce') return 'E-Commerce';
    if (lt === 'local_business') return 'Lokales Geschäft';
    if (lt === 'marketing') return 'Marketing';
  }
  const query = (searchQuery || '').toLowerCase();
  if (/physio|therapie|reha/i.test(query)) return 'Physiotherapie';
  if (/immobilie|makler|estate/i.test(query)) return 'Immobilienmakler';
  if (/coach|beratung|consult/i.test(query)) return 'Coaching';
  if (/zeitarbeit|personal|arbeitnehmer|recruiting/i.test(query)) return 'Zeitarbeit';
  if (/saas|software|app|platform/i.test(query)) return 'SaaS';
  if (/investor|vc|venture|capital/i.test(query)) return 'Investor';

  const text = [ (services||[]).join(' '), companyName||'', topService||'' ].join(' ').toLowerCase();
  if (/marketing|ads|performance|seo|sea|social media/i.test(text)) return 'Marketing';
  return 'Sonstiges';
}

