// ========== NAME VALIDIERUNG FUNKTIONEN ==========
const NAME_BLACKLIST = [
  'tobias dziuba', 'max mustermann', 'john doe', 'jane doe',
  'test user', 'admin', 'webmaster', 'support', 'administrator',
  'info info', 'contact contact', 'real estate', 'toronto real',
