  'your name', 'first last', 'name here'
];

function isValidPersonName(name) {
  if (!name) return false;

  const nameLower = name.toLowerCase().trim();

  // Blacklist check
  if (NAME_BLACKLIST.some(b => nameLower.includes(b) || b.includes(nameLower))) {
    console.warn('   ⚠️ Blacklisted name:', name);
    return false;
  }

  // Muss 2-4 Wörter haben
  const parts = name.trim().split(/\s+/);
  if (parts.length < 2 || parts.length > 4) {
    console.warn('   ⚠️ Invalid word count:', name, '(', parts.length, 'words)');
    return false;
  }

  // Keine Zahlen
  if (/\d/.test(name)) {
    console.warn('   ⚠️ Name contains numbers:', name);
    return false;
  }

  // Mindestens 5 Zeichen
  if (name.length < 5) {
    console.warn('   ⚠️ Name too short:', name);
    return false;
  }

  // Keine typischen Firmennamen-Wörter
  const companyWords = ['llc', 'inc', 'gmbh', 'ag', 'ltd', 'corp', 'estate', 'realty', 'group', 'team', 'agency', 'solutions'];
  if (companyWords.some(w => nameLower.includes(w))) {
    console.warn('   ⚠️ Name contains company word:', name);
    return false;
  }

  // ✅ Wörter validieren (Bindestrich und Apostroph erlaubt)
  // Beispiele: "Hitzler-Wegerer", "O'Brian", "McDonald"
  const tokenRe = /^[A-ZÄÖÜ][a-zäöüß]+(?:[-'][A-ZÄÖÜ]?[a-zäöüß]+)*$/;

  for (const part of parts) {
    if (!tokenRe.test(part)) {
      console.warn('   ⚠️ Invalid name format:', name, '| Bad token:', part);
      return false;
    }
  }

  return true;
}

function isBlacklistedName(name) {
  if (!name) return false;
  const nameLower = name.toLowerCase().trim();
  return NAME_BLACKLIST.some(blocked => nameLower.includes(blocked));
}

