// Build Candidate Pages – FIXED v7 (richtige Ziel-Domain + interne Crawl-URLs filtern)

const MAX_PAGES = 10;

function toStr(v) {
  if (v === null || v === undefined) return '';
  if (Array.isArray(v)) return v.join('\n');
  return String(v).trim();
}

function cleanUrl(url) {
  if (!url) return '';
  let s = String(url)
    .replace(/[\r\n\t\s]+/g, '')
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, '')
    .replace(/\u200B/g, '')
    .replace(/\uFEFF/g, '')
    .trim();

  s = s.replace(/\/+$/, '');
  return s;
}

function normalizeHttp(url) {
  let u = cleanUrl(url);
  if (!u) return '';
  if (!/^https?:\/\//i.test(u)) u = 'https://' + u;
  return u;
}

function isInternalCrawlUrl(u) {
  const s = String(u || '');
  return /crawl\.alphamindhub\.com\/v2\/crawl\//i.test(s) || /n8n\.getvoidra\.com/i.test(s);
}

function extractUrlFromJinaText(text) {
  const s = toStr(text);
  const m = s.match(/URL Source:\s*(https?:\/\/[^\s\n]+)/i);
  return m ? cleanUrl(m[1]) : null;
}

function getOrigin(urlString) {
  const cleaned = cleanUrl(urlString);
  if (!cleaned) return null;
  try {
    const u = new URL(cleaned);
    return u.origin;
  } catch (e) {
    const match = cleaned.match(/^(https?:\/\/[^\/\?\#]+)/i);
    return match ? match[1] : null;
  }
}

function isBadPath(path) {
  const t = path.toLowerCase();
  const bad = [
    'myportal','portal','login','signin','sign-in',
    'account','wp-login','wp-admin','admin','dashboard',
    'cart','checkout','warenkorb','password','register'
  ];
  return bad.some(b => t.includes(b));
}

function pickBaseUrl(item) {
  const j = item.json || {};

  // 1) HARTE Priorität: echte Zielsite-Felder
  const highPriority = [
    j.extracted_url,
    j?.metadata?.site,
    j.site,
    j.source_site,
    j.website,
    j.original_url,
    j.final_url,
  ].map(normalizeHttp).filter(Boolean);

  for (const u of highPriority) {
    if (isInternalCrawlUrl(u)) continue;
    return { url: u, source: 'high_priority' };
  }

  // 2) Wenn gar nichts: Versuch aus Text (Jina Output)
  const textFields = ['data', 'body', 'markdown', 'text', 'raw_text'];
  for (const f of textFields) {
    const extracted = extractUrlFromJinaText(j[f]);
    if (extracted && !isInternalCrawlUrl(extracted)) {
      return { url: normalizeHttp(extracted), source: 'extracted_from:' + f };
    }
  }

  // 3) Letzte Notlösung: url / base_url, aber Crawl-URLs rausfiltern
  const lowPriority = [j.url, j.base_url, j.clean_target_url].map(normalizeHttp).filter(Boolean);
  for (const u of lowPriority) {
    if (isInternalCrawlUrl(u)) continue;
    return { url: u, source: 'low_priority' };
  }

  return null;
}

// ========== MAIN ==========
const items = $input.all();
const validCandidates = [];

for (const item of items) {
  const j = item.json || {};

  const baseUrlResult = pickBaseUrl(item);
  if (!baseUrlResult) continue;

  const origin = getOrigin(baseUrlResult.url);
  if (!origin) continue;

  const paths = [
    // Kontakt
    '/contact','/contact-us','/kontakt','/get-in-touch','/reach-us',

    // Impressum/Legal
    '/impressum','/imprint','/legal','/legal-notice',

    // Datenschutz/Privacy
    '/datenschutz','/datenschutzerklaerung','/privacy','/privacy-policy','/data-privacy',

    // About/Team
    '/about','/about-us','/ueber-uns','/team','/our-team'
  ];

  const candidates = [];
  const seen = new Set();

  for (const p of paths) {
    if (isBadPath(p)) continue;
    const fullUrl = origin + p;
    if (seen.has(fullUrl)) continue;
    seen.add(fullUrl);
    candidates.push(fullUrl);
    if (candidates.length >= MAX_PAGES) break;
  }

  if (candidates.length === 0) candidates.push(origin + '/contact');

  for (const url of candidates) {
    validCandidates.push({
      json: {
        ...j,
        candidate_url: url,
        base_url: origin + '/',
        origin,
        _jina_stage: 'candidate',
        _url_source: baseUrlResult.source,
      }
    });
  }
}

if (validCandidates.length === 0) {
  return [{
    json: {
      _no_candidates: true,
      candidate_url: 'https://example.com/skip',
      _skip_jina_fetch: true
    }
  }];
}

return validCandidates;

// ==========================================
// MERGE JINA + FIRECRAWL DATA
// ==========================================

const jinaData = $json; // Jina Output

// Firecrawl-Daten aus dem Input-Flow holen
