            firecrawlData.all_contacts?.map(c => c.name).join(', ') || 'none');
console.log('   Jina emails:', jinaData.emails?.join(', ') || jinaData.primary_email || 'none');

// Emails aus Jina extrahieren
const jinaEmails = [
  jinaData.primary_email,
  jinaData.ceo_email,
  ...(jinaData.emails || []),
  ...(jinaData.all_emails || [])
].filter(e => e && String(e).includes('@'));

// Merged Output
return {
  json: {
    // === NAMEN AUS FIRECRAWL ===
    ceo_name: firecrawlData.primary_contact_name || jinaData.ceo_name || null,
    primary_contact_name: firecrawlData.primary_contact_name || jinaData.primary_contact_name || null,

    // === EMAILS AUS JINA ===
    ceo_email: jinaEmails[0] || null,
    best_email: jinaEmails[0] || null,
    all_emails: [...new Set(jinaEmails)],

    // === COMPANY ===
    company_name: firecrawlData.company_name || jinaData.company_name || null,

    // === ALLE KONTAKTE (Firecrawl + Jina Emails) ===
    all_contacts: (firecrawlData.all_contacts || []).map((contact, idx) => ({
      ...contact,
      // Versuche Email aus Jina zuzuordnen
      email: contact.email || jinaEmails[idx] || null
    })),

    // === SERVICES & SOCIAL (aus Firecrawl) ===
    services: firecrawlData.services || jinaData.services || [],
    social_media: firecrawlData.social_media || jinaData.social_media || {},

    // === META ===
    website: firecrawlData.website || jinaData.website || jinaData.final_url || null,
    final_url: jinaData.final_url || firecrawlData.website || null,

    // Für Unified Contact Extraction
    _firecrawl_data: firecrawlData,
    _jina_data: jinaData,

    contact_source: 'firecrawl+jina',
    source: 'merged'
  }
};

