// n8n Code node (Run Once for All Items)
// Goal: clean links (remove images/assets), extract emails + sane phones
// ✅ MIT __keep DURCHREICHUNG

function toStr(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function uniq(arr) {
  return [...new Set(arr.filter(Boolean))];
}

function normalizeUrl(u) {
  u = toStr(u).trim();
  if (!u) return null;
  u = u.replace(/[)\],.]+$/g, '');
  u = u.replace(/\/+$/g, '');
  return u || null;
}

function isAssetUrl(u) {
  if (!u) return true;
  const s = u.toLowerCase();
  if (/\.(png|jpg|jpeg|gif|webp|svg|ico|pdf|mp4|mov|avi|woff2?|ttf|eot)(\?|#|$)/i.test(s)) return true;
  if (s.includes('framerusercontent.com/images/')) return true;
  if (s.startsWith('data:')) return true;
  return false;
}

function extractEmailsFromText(text) {
  const s = toStr(text);
  if (!s) return [];
  const matches = s.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi) || [];
  return matches.map(e => e.replace(/[)\],.]+$/g, '').toLowerCase());
}

function extractEmailsFromLinks(links) {
  const out = [];
  for (const l of links || []) {
    const s = toStr(l);
    const m = s.match(/mailto:([^?]+)/i);
    if (m && m[1]) out.push(m[1]);
  }
  return out.map(e => e.replace(/[)\],.]+$/g, '').toLowerCase());
}

function extractPhonesFromText(text) {
  const s = toStr(text);
  if (!s) return [];

  const candidates = s.match(/(\+?\d[\d\s().-]{6,}\d)/g) || [];

  const cleaned = candidates
    .map(x => x.replace(/[^\d+]/g, ''))
    .map(x => x.replace(/^00/, '+'))
    .filter(x => {
      const digits = x.replace(/\+/g, '');
      if (digits.length < 7 || digits.length > 15) return false;
      if (!x.startsWith('+')) {
        if (/^(1024|1152|480|774|2946|4590|281|482)\d+$/g.test(digits)) return false;
      }
      return true;
    });

  return cleaned;
}

const items = $input.all();

return items.map((item) => {
  const j = item.json || {};
  const keep = j.__keep || {};

  const text = [
    j.text,
    j.snippet,
    j.meta_description,
    j.html,
    j.content
  ].map(toStr).join(' ');

  const rawLinks = Array.isArray(j.links) ? j.links : [];
  const links = uniq(
    rawLinks
      .map(normalizeUrl)
      .filter(u => u && !isAssetUrl(u))
  );

  const emails = uniq([
    ...extractEmailsFromLinks(rawLinks),
    ...extractEmailsFromText(text),
    ...(Array.isArray(j.emails) ? j.emails.map(e => toStr(e).toLowerCase()) : [])
  ]);

  const phones = uniq([
    ...extractPhonesFromText(text),
    ...(Array.isArray(j.phones) ? j.phones.map(toStr) : [])
  ]);

  return {
    json: {
      ...j,
      links,
      emails,
      phones,
      // ✅ Metadata durchreichen
      __keep: keep,
      lead_type: j.lead_type || keep.lead_type || null,
      category: j.category || keep.category || null,
      status: j.status || keep.status || null,
      icebreaker: j.icebreaker || keep.icebreaker || null,
      city: j.city || keep.city || null
    }
  };
});

