const quelle     = cleanStr(ai.quelle)     ?? cleanStr(keep.quelle)     ?? cleanStr(pre.quelle);
const nische     = cleanStr(ai.nische)     ?? cleanStr(keep.nische)     ?? cleanStr(pre.nische);
const row_number = cleanStr(ai.row_number) ?? cleanStr(keep.row_number) ?? cleanStr(pre.row_number);

