const mobile_phone  = cleanStr(pre.mobile_phone)  ?? cleanStr(ai.mobile_phone);

const whatsapp_possible =
  (typeof pre.whatsapp_possible === "boolean") ? pre.whatsapp_possible :
  (typeof ai.whatsapp_possible === "boolean") ? ai.whatsapp_possible :
  undefined;

const social_media = pre.social_media || ai.social_media || undefined;
const page_stats   = pre._page_stats || ai._page_stats || undefined;

