function uniq(a){ 
  return Array.from(new Set((a||[]).filter(Boolean).map(s=>String(s).trim()))); 
}

function shortify(s,n=12){ 
  return String(s||'').replace(/\s+/g,' ').trim().split(' ').slice(0,n).join(' '); 
}

function parseAI(j){
  if (!j) return {};
  if (j.output !== undefined && j.output !== null) {
    if (typeof j.output === 'string' && j.output.trim()) {
      try { return JSON.parse(j.output); } catch(e) {}
    }
    if (typeof j.output === 'object' && Object.keys(j.output).length > 0) return j.output;
  }
  if (j.message && j.message.content) {
    if (typeof j.message.content === 'string') {
      try { return JSON.parse(j.message.content); } catch(e) {}
    }
    if (typeof j.message.content === 'object') return j.message.content;
  }
  if (typeof j === 'string' && j.trim()) {
    try { return JSON.parse(j); } catch(e) {}
  }
  if (typeof j === 'object') return j;
  return {};
}

function domain(u){ 
  try{ return new URL(u).hostname.replace(/^www\./,''); } 
  catch(e) { return ''; } 
}

function domainNameFromUrl(u){
  const d = domain(u); 
  if(!d) return null;
  return d.split('.').slice(0,-1).join(' ')
          .split(/[-_]/).map(w=>w.charAt(0).toUpperCase()+w.slice(1)).join(' ');
}

