// ========== INPUT DETECTION (unwrap Email Validator) ==========
const rawInput = $input.first().json || {};

// Wenn Input vom Email Validator kommt:
const currentInput = (rawInput.originalData && typeof rawInput.originalData === 'object')
  ? {
      ...rawInput.originalData,
      validated_email: rawInput.email || null,
      email_status: rawInput.email_status || null,
    }
  : rawInput;

// ✅ IMPORTANT: KEEP META RETRIEVAL
const keepFromOriginal = (rawInput.originalData && rawInput.originalData._keep && typeof rawInput.originalData._keep === 'object')
  ? rawInput.originalData._keep
  : null;

const keepFromCurrent = (currentInput._keep && typeof currentInput._keep === 'object')
  ? currentInput._keep
  : null;

const _keep = {
  ...(keepFromOriginal || {}),
  ...(keepFromCurrent || {}),
};

// ========== ICEBREAKER RETTEN ==========
let icebreaker = null;
if (typeof currentInput.icebreaker === 'string') icebreaker = currentInput.icebreaker;
else if (currentInput.message?.content?.icebreaker && typeof currentInput.message.content.icebreaker === 'string') icebreaker = currentInput.message.content.icebreaker;
else if (rawInput.output?.icebreaker && typeof rawInput.output.icebreaker === 'string') icebreaker = rawInput.output.icebreaker;

// ========== LEAD TYPE RETTEN ==========
let lead_type = currentInput.lead_type || _keep.lead_type || rawInput.lead_type || null;

// ========== FLOW PATH (dein alter Code: fallback) ==========
let flowPath = 'unknown';
let prep = { pages:[], emails:[], source_site:null, crawl_id:null };
let aiData = {};

if (currentInput.contact_source || currentInput.source_priority || currentInput._original_source) {
  flowPath = 'fallback';

  aiData = {
    company_name: currentInput.company_name || null,
    ceo_name: currentInput.ceo_name || currentInput.primary_contact_name || currentInput.contact_name || null,
    first_name: currentInput.first_name || '',
    last_name: currentInput.last_name || '',
    services: currentInput.services || [],
    emails: currentInput.emails || [currentInput.best_email].filter(Boolean),
    top_location: currentInput.top_location || currentInput.address || null,
    top_service: currentInput.top_service || (currentInput.services && currentInput.services[0]) || null,
    unique_points: currentInput.description ? [currentInput.description] : [],
    recent_items: [],
    quotes: [],
    evidence_urls: [],

    // social
    ceo_linkedin: currentInput.ceo_linkedin || null,
    ceo_xing: currentInput.ceo_xing || null,
    social_media_company: currentInput.social_media_company || {}
  };

  const website =
    currentInput.website ||
    currentInput.original_url ||
    currentInput.source_site ||
    _keep.site ||
    _keep.source_site ||
    webhookWebsite ||
    '';

  prep = {
    pages: [{
      url: website,
      title: currentInput.company_name || '',
      text: currentInput.description || ''
    }],
    emails: aiData.emails,
    source_site: website,
    crawl_id: currentInput.crawl_id || _keep.crawl_id || webhookCrawlId || null
  };
}

// ========== PROCESS DATA ==========
const extracted = parseAI(aiData || {});

// ✅ URL mit Webhook-Fallback
const firstUrl =
  (prep.pages?.[0]?.url) ||
  prep.source_site ||
  currentInput.website ||
  currentInput.source_site ||
  _keep.site ||
  _keep.source_site ||
  webhookWebsite ||
  '';

let company_name = extracted.company_name || currentInput.company_name || null;
if (!company_name || placeholder(company_name)) company_name = domainNameFromUrl(firstUrl);

const services      = uniq(extracted.services || currentInput.services || []).slice(0,8);
const unique_points = uniq(extracted.unique_points || []).slice(0,5);
const recent_items  = uniq(extracted.recent_items || []).slice(0,3);
const quotes        = uniq(extracted.quotes || []).slice(0,2);
const evidence_urls = uniq(extracted.evidence_urls || []).slice(0,5);

// ✅ EMAILS sammeln
const emails = uniq([
  ...(extracted.emails||[]).map(e => String(e).toLowerCase()),
  ...(prep.emails||[]).map(e => String(e).toLowerCase()),
  ...(currentInput.emails||[]).map(e => String(e).toLowerCase())
]);

// ✅ BEST EMAIL – validierte Email wird bevorzugt
let best_email = null;
if (currentInput.validated_email && currentInput.email_status === 'valid') {
  best_email = currentInput.validated_email;
} else {
  best_email =
    currentInput.best_email ||
    currentInput.primary_email ||
    currentInput.ceo_email ||
    emails.find(e => /(owner|inhaber|ceo|founder|geschäftsführer|geschaeftsfuehrer)/i.test(e)) ||
    emails.find(e => /^(kontakt|office|hello)@/i.test(e)) ||
    emails.find(e => /^info@/i.test(e)) ||
    emails[0] ||
    null;
}

// social
const ceo_linkedin = currentInput.ceo_linkedin || extracted.ceo_linkedin || null;
const ceo_xing = currentInput.ceo_xing || extracted.ceo_xing || null;

const social_media_company = currentInput.social_media_company || extracted.social_media_company || {
  linkedin_company: null,
  facebook: null,
  instagram: null,
  twitter: null,
  youtube: null,
  xing_company: null,
  tiktok: null,
  pinterest: null
};

// rest
const fact_pool = uniq([
  ...quotes, ...recent_items,
  ...((prep.pages||[]).flatMap(p => [p.title, shortify(p.text)]))
]).slice(0,12);

const proof_url    = evidence_urls[0] || firstUrl || null;
const top_location = extracted.top_location || currentInput.top_location || null;
const top_service  = extracted.top_service || (services[0] || null);

const crawl_id =
  prep.crawl_id ||
  currentInput.crawl_id ||
  _keep.crawl_id ||
  webhookCrawlId ||
  null;

const source_site =
  prep.source_site ||
  currentInput.source_site ||
  currentInput.website ||
  _keep.source_site ||
  _keep.site ||
  firstUrl ||
  null;

// names
const first_name = currentInput.first_name || extracted.first_name || '';
const last_name = currentInput.last_name || extracted.last_name || '';
const ceo_name = currentInput.ceo_name || currentInput.primary_contact_name || extracted.ceo_name || null;

// city / status / category / icebreaker meta
const city =
  currentInput.contact_location ||
  currentInput.top_location ||
  _keep.city ||
  null;

const category =
  currentInput.category ||
  _keep.category ||
  null;

const status =
  currentInput.status ||
  _keep.status ||
  null;

// ✅ keep update (write back the freshest truth)
const keepOut = {
  ..._keep,
  lead_type: lead_type || _keep.lead_type || null,
  category: category || _keep.category || null,
  status: status || _keep.status || null,
  icebreaker: (icebreaker ?? _keep.icebreaker ?? null),
  city: city || _keep.city || null,
  site: _keep.site || source_site || null,
  crawl_id: crawl_id || _keep.crawl_id || null,
  source_site: _keep.source_site || source_site || null,
};

// return
return [{
  json: {
    // ✅ META THROUGH (top-level mirrors)
    lead_type: keepOut.lead_type,
    category: keepOut.category,
    status: keepOut.status,
    city: keepOut.city,
    site: keepOut.site,
    crawl_id: keepOut.crawl_id,
    source_site: keepOut.source_site,
    icebreaker: keepOut.icebreaker,

    // ✅ KEEP OBJECT THROUGH
    _keep: keepOut,

    // ========== BASIC INFO ==========
    company_name,
    lang: currentInput.lang || 'de',

    // ========== CONTACT INFO ==========
    ceo_name,
    first_name,
    last_name,
    best_email,
    emails,

    // social
    ceo_linkedin,
    ceo_xing,
    social_media_company,

    // location/services/content
    top_location,
    top_service,
    services,
    unique_points,
    recent_items,
    quotes,
    evidence_urls,
    fact_pool,
    proof_url,

    // pass-through
    all_decision_makers: currentInput.all_decision_makers || [],
    all_locations: currentInput.all_locations || [],

    // debug
    flow_path: flowPath,
    _input_source: currentInput.contact_source || currentInput.source_priority || 'firecrawl',
  }
}];

const items = $input.all();

const domains = [];
for (const item of items) {
  // Sheet hat "Website" mit großem W!
  const url = item.json.Website || '';

  if (url) {
    const domain = url
      .toLowerCase()
      .replace(/^https?:\/\//, '')
      .replace(/^www\./, '')
      .split('/')[0];

    if (domain) {
      domains.push(domain);
    }
  }
}

console.log('📊 Domains aus Sheet:', domains.length);
console.log('🔍 Erste 5:', domains.slice(0, 5));

return [{ json: { existingDomains: domains } }];

// =====================================================
// FINAL DETERMINISTIC MAPPER (FIXED FOR { ai, pre } WRAP)
// + ROLE FALLBACK: "Vertreten durch:" => Geschäftsführer
// Mode: runOnceForEachItem
// =====================================================

const raw = $json || {};

// 1) Extract AI payload safely (your structure is raw.ai.message.content)
const d =
  (raw?.ai?.message?.content && typeof raw.ai.message.content === "object") ? raw.ai.message.content :
  (raw?.ai?.content && typeof raw.ai.content === "object") ? raw.ai.content :
  (raw?.message?.content && typeof raw.message.content === "object") ? raw.message.content :
  (raw?.content && typeof raw.content === "object") ? raw.content :
  raw;

// 2) Extract PRE metadata safely
const pre = raw.pre || {};
const preKeep = pre._keep || pre.__keep || {};
const keepFromRaw = raw._keep || raw.__keep || {}; // fallback (usually empty)
const keep = { ...preKeep, ...keepFromRaw }; // PRE wins

function isNonEmptyStr(x) {
  return typeof x === "string" && x.trim().length > 0;
}

function normEmail(e) {
  if (!isNonEmptyStr(e)) return null;
  return e.trim().toLowerCase();
}

function looksLikeRealEmail(e) {
  if (!isNonEmptyStr(e)) return false;
  const s = e.trim().toLowerCase();
  if (!s.includes("@")) return false;
  if (s.endsWith(".jpg") || s.endsWith(".png") || s.endsWith(".webp") || s.endsWith(".svg")) return false;
  if (s.includes("@2x.")) return false;
  return true;
}

function pickFirst(arr, predicate) {
  if (!Array.isArray(arr)) return null;
  for (const x of arr) if (predicate(x)) return x;
  return null;
}

// -------- DECISION MAKERS ----------
let decisionMakers = Array.isArray(d.decision_makers) ? d.decision_makers : [];

// --- ROLE FALLBACK aus Impressum: "Vertreten durch:" => Geschäftsführer
const pagesPre = Array.isArray(pre.pages) ? pre.pages : [];
const impressumText = pagesPre
  .filter(p => String(p.pageType || "").toLowerCase() === "impressum")
  .map(p => `${p.title || ""}\n${p.text || ""}`)
  .join("\n")
  .toLowerCase();

const hasVertretenDurch = impressumText.includes("vertreten durch");

function roleFallback(dm) {
  if (!dm || typeof dm !== "object") return dm;
  const role = (dm.role && String(dm.role).trim()) ? String(dm.role).trim() : null;
  if (role) return dm;

  // Wenn im Impressum "Vertreten durch" steht, setzen wir eine valide Rolle
  if (hasVertretenDurch) {
    return { ...dm, role: "Geschäftsführer" };
  }
  return dm;
}

// fallback auf alle DMs anwenden
decisionMakers = decisionMakers.map(roleFallback);

// -------- PRIMARY DECISION MAKER ----------
const primaryDM =
  pickFirst(decisionMakers, x =>
    isNonEmptyStr(x?.first_name) &&
    isNonEmptyStr(x?.last_name) &&
    isNonEmptyStr(x?.role) &&
    String(x?.source_type || "").toLowerCase() === "impressum"
  ) ||
  pickFirst(decisionMakers, x =>
    isNonEmptyStr(x?.first_name) &&
    isNonEmptyStr(x?.last_name) &&
    isNonEmptyStr(x?.role)
  ) ||
  null;

// -------- EMAILS ----------
const emailsRaw = Array.isArray(d.emails) ? d.emails : [];

const emails = emailsRaw
  .map(x => ({
    email: normEmail(x?.email),
    source_url: x?.source_url ?? null,
    source_type: x?.source_type ?? null
  }))
  .filter(x => looksLikeRealEmail(x.email));

function emailRank(email) {
  if (!isNonEmptyStr(email)) return 999;
  const local = email.split("@")[0].toLowerCase();

  if (["info", "kontakt", "contact", "hello", "mail", "office"].includes(local)) return 1;
  if (["anfrage", "sales", "support", "service"].includes(local)) return 2;
  return 5;
}

function pickBestEmailBySource(type) {
  const subset = emails.filter(x => String(x.source_type || "").toLowerCase() === type);
  if (!subset.length) return null;
  subset.sort((a, b) => emailRank(a.email) - emailRank(b.email));
  return subset[0];
}

const generalEmailObj =
  pickBestEmailBySource("impressum") ||
  pickBestEmailBySource("contact") ||
  (() => {
    if (!emails.length) return null;
    emails.sort((a, b) => emailRank(a.email) - emailRank(b.email));
    return emails[0];
  })();

const otherEmails = emails
  .filter(x => x.email && x.email !== (generalEmailObj?.email ?? null))
  .filter((x, idx, arr) => arr.findIndex(y => y.email === x.email) === idx)
  .slice(0, 5);

// -------- PHONES ----------
const phonesRaw = Array.isArray(d.phones) ? d.phones : [];

const phones = phonesRaw
  .map(x => ({
    phone: isNonEmptyStr(x?.phone) ? x.phone.trim() : null,
    source_url: x?.source_url ?? null,
    source_type: x?.source_type ?? null
  }))
  .filter(x => isNonEmptyStr(x.phone));

function pickBestPhoneBySource(type) {
  return pickFirst(phones, x => String(x.source_type || "").toLowerCase() === type);
}

const generalPhoneObj =
  pickBestPhoneBySource("impressum") ||
  pickBestPhoneBySource("contact") ||
  (phones.length ? phones[0] : null);

// -------- OUTPUT ----------
const out = {
  company_name: d.company_name ?? null,
  domain: d.domain ?? null,
  language_guess: d.language_guess ?? null,

  primary_decision_maker: {
    first_name: primaryDM?.first_name ?? null,
    last_name: primaryDM?.last_name ?? null,
    role: primaryDM?.role ?? null,

    email: generalEmailObj?.email ?? null,
    phone: generalPhoneObj?.phone ?? null,

    name_source_url: primaryDM?.source_url ?? null,
    name_source_type: primaryDM?.source_type ?? null,

    email_source_url: generalEmailObj?.source_url ?? null,
    email_source_type: generalEmailObj?.source_type ?? null,

    phone_source_url: generalPhoneObj?.source_url ?? null,
    phone_source_type: generalPhoneObj?.source_type ?? null
  },

  contacts: {
    general_email: generalEmailObj?.email ?? null,
    general_email_source_url: generalEmailObj?.source_url ?? null,
    general_email_source_type: generalEmailObj?.source_type ?? null,

    general_phone: generalPhoneObj?.phone ?? null,
    general_phone_source_url: generalPhoneObj?.source_url ?? null,
    general_phone_source_type: generalPhoneObj?.source_type ?? null,

    other_emails: otherEmails.map(x => ({
      email: x.email,
      source_url: x.source_url ?? null,
      source_type: x.source_type ?? null
    }))
  }
};

// ✅ KEEP ROUTING/META ALIVE (from PRE!)
out._keep = keep;
out.__keep = keep;

// Top-level routing fields (prefer PRE, then keep)
out.lead_type   = pre.lead_type   ?? keep.lead_type   ?? null;
out.category    = pre.category    ?? keep.category    ?? null;
out.status      = pre.status      ?? keep.status      ?? null;
out.city        = pre.city        ?? keep.city        ?? null;
out.quelle      = pre.quelle      ?? keep.quelle      ?? null;
out.nische      = pre.nische      ?? keep.nische      ?? null;
out.row_number  = pre.row_number  ?? keep.row_number  ?? null;
out.source_site = pre.source_site ?? keep.source_site ?? null;
out.crawl_id    = pre.crawl_id    ?? keep.crawl_id    ?? null;

return {
  json: {
    pre,          // original PRE payload
    ai: out       // dein final gemapptes Ergebnis
  }
};

// =====================================================
// Quality Check (V3) - CURRENT SCHEMA
// Mode: runOnceForEachItem
// =====================================================

const d = $json || {};

function isNonEmptyStr(x) {
  return typeof x === "string" && x.trim().length > 0;
}

function looksLikeRealEmail(e) {
  if (!isNonEmptyStr(e)) return false;
  const s = e.trim().toLowerCase();
  if (!s.includes("@")) return false;
  if (s.endsWith(".jpg") || s.endsWith(".png") || s.endsWith(".webp") || s.endsWith(".svg")) return false;
  if (s.includes("@2x.")) return false;
  return true;
}

function hasValidEmailInOtherEmails(arr) {
  if (!Array.isArray(arr)) return false;
  return arr.some(x => looksLikeRealEmail(x?.email));
}

const pdm = (d.primary_decision_maker && typeof d.primary_decision_maker === "object")
  ? d.primary_decision_maker
  : {};

const contacts = (d.contacts && typeof d.contacts === "object")
  ? d.contacts
  : {};

// ✅ FIX: other_emails liegt bei dir unter contacts.other_emails
const otherEmailsArr = Array.isArray(contacts.other_emails) ? contacts.other_emails : [];

const hasDecisionMaker =
  isNonEmptyStr(pdm.first_name) &&
  isNonEmptyStr(pdm.last_name) &&
  isNonEmptyStr(pdm.role);

const hasAnyEmail =
  looksLikeRealEmail(pdm.email) ||
  looksLikeRealEmail(contacts.general_email) ||
  hasValidEmailInOtherEmails(otherEmailsArr);

const hasAnyPhone =
  isNonEmptyStr(pdm.phone) ||
  isNonEmptyStr(contacts.general_phone);

const stats = d._page_stats || null;
const selectedCount =
  (stats && typeof stats.selected_for_ai === "number") ? stats.selected_for_ai :
  (Array.isArray(d.pages) ? d.pages.length : null);

const qc_reasons = [];

if (!hasDecisionMaker) qc_reasons.push("missing_decision_maker");
if (!hasAnyEmail) qc_reasons.push("missing_email");

if (!hasAnyPhone) qc_reasons.push("missing_phone");
if (typeof selectedCount === "number" && selectedCount < 2) qc_reasons.push("too_few_pages_selected");

const trigger_perplexity =
  qc_reasons.includes("missing_decision_maker") ||
  qc_reasons.includes("missing_email");

d.trigger_perplexity = trigger_perplexity;
d.qc_reasons = qc_reasons;

// keep routing fields alive
const keep = d._keep || d.__keep || {};
d.lead_type = d.lead_type || keep.lead_type || null;
d.crawl_id = d.crawl_id || keep.crawl_id || null;
d.source_site = d.source_site || keep.source_site || null;

// write both keep keys
if (!d._keep) d._keep = keep;
d.__keep = d._keep;

return { json: d };

