/**
 * Prepare for AnyMailFinder Verify (NO EXPAND)
 * Mode: Run Once for All Items
 *
 * Output: 1 item per company, with:
 * - email_candidates (deduped)
 * - email_candidate_index (pointer)
 * - email_to_verify (current candidate)
 * - email_done / email_exhausted
 * - _domain, _source_url, _company
 * - amf { domain, email, ... }
 */

function toStr(v) {
  return v === null || v === undefined ? "" : String(v).trim();
}

function pickFirst(...vals) {
  for (const v of vals) {
    const s = toStr(v);
    if (s) return s;
  }
  return "";
}

function normalizeUrl(u) {
  let x = toStr(u);
  if (!x) return "";
  if (!/^https?:\/\//i.test(x)) x = "https://" + x;
  try {
    return new URL(x).toString();
  } catch {
    return "";
  }
}

function extractDomain(input) {
  const raw = toStr(input).replace(/^mailto:/i, "").replace(/^tel:/i, "");
  if (!raw) return "";

  const looksLikeDomain = /^[a-z0-9.-]+\.[a-z]{2,}$/i.test(raw);
  if (looksLikeDomain) return raw.toLowerCase().replace(/^www\./i, "");

  const u = normalizeUrl(raw);
  if (!u) return "";
  try {
    const url = new URL(u);
    return (url.hostname || "").toLowerCase().replace(/^www\./i, "");
  } catch {
    return "";
  }
}

function uniqEmails(arr) {
  const out = [];
  const seen = new Set();
  for (const x of arr) {
    const e = toStr(x).toLowerCase();
    if (!e) continue;
    if (seen.has(e)) continue;
    seen.add(e);
    out.push(e);
  }
  return out;
}

const items = $input.all();
const out = [];

for (const item of items) {
  const j = item.json || {};

  // Website Sources
  const sourceWebsite = pickFirst(
    j.website, j.url, j.domain, j.homepage, j.site, j.source_site, j.original_url,
    j?._keep?.site, j?.__keep?.site,
    j?._keep?.source_site, j?.__keep?.source_site
  );

  const sourceUrl = normalizeUrl(sourceWebsite);
  const domain = extractDomain(sourceWebsite) || extractDomain(j.domain);

  const company = pickFirst(
    j.company_name, j.company, j.name, j.business_name, j.firma, j.Company,
    j?._keep?.company_name, j?.__keep?.company_name,
    j?._company
  );

  const firstName = pickFirst(j.firstName, j.firstname, j.vorname, j.first_name);
  const lastName  = pickFirst(j.lastName, j.lastname, j.nachname, j.last_name);
  const fullName  = [firstName, lastName].filter(Boolean).join(" ").trim();

  const rowId = pickFirst(
    j.rowId, j.row_id, j.id, j.ID, j.sheetRowId, j._rowId, j._id,
    j?._keep?.row_number, j?.__keep?.row_number
  );

  // Kandidaten einsammeln
  const candidatesRaw = []
    .concat(Array.isArray(j.email_candidates) ? j.email_candidates : [])
    .concat(Array.isArray(j.emails) ? j.emails : [])
    .concat(Array.isArray(j.all_emails) ? j.all_emails : [])
    .concat([j.best_email, j.primary_email, j.ceo_email, j.email_to_verify]);

  const emailCandidates = uniqEmails(candidatesRaw);

  // Wenn keine Kandidaten -> "fertig"
  if (emailCandidates.length === 0) {
    out.push({
      json: {
        ...j,
        _domain: domain,
        _source_url: sourceUrl,
        _company: company,

        email_candidates: [],
        email_candidate_index: -1,
        email_to_verify: null,

        email_done: true,
        email_exhausted: true,

        amf: {
          domain: domain || undefined,
          company: company || undefined,
          firstName: firstName || undefined,
          lastName: lastName || undefined,
          fullName: fullName || undefined,
          sourceUrl: sourceUrl || undefined,
          rowId: rowId || undefined,
          meta: {
            preparedAt: new Date().toISOString(),
            amfReady: false,
            inputWebsite: sourceWebsite || undefined,
          },
        },
      },
    });
    continue;
  }

  // ✅ 1 Item pro Firma, Start bei Kandidat 0
  out.push({
    json: {
      ...j,
      _domain: domain,
      _source_url: sourceUrl,
      _company: company,

      email_candidates: emailCandidates,
      email_candidate_index: 0,
      email_to_verify: emailCandidates[0],

      email_done: false,
      email_exhausted: false,

      amf: {
        domain: domain || undefined,
        email: emailCandidates[0] || undefined,
        company: company || undefined,
        firstName: firstName || undefined,
        lastName: lastName || undefined,
        fullName: fullName || undefined,
        sourceUrl: sourceUrl || undefined,
        rowId: rowId || undefined,
        meta: {
          preparedAt: new Date().toISOString(),
          amfReady: Boolean(domain && emailCandidates[0]),
          inputWebsite: sourceWebsite || undefined,
        },
      },
    },
  });
}

// ── Kontext für HTTP-Request-Überleben sichern ──
