function cleanPhone(v) {
  if (!v) return null;
  let s = String(v).trim();
  s = s.replace(/[^\d+]/g, ""); // keep digits and +
  if (s.startsWith("0049")) s = "+49" + s.slice(4);
  if (/^0\d{6,}$/.test(s)) s = "+49" + s.slice(1);
  const digits = s.replace(/[^\d]/g, "");
  if (digits.length < 10) return null;
  return s;
}

// filter crawler garbage like +2020..., +2011... from image timestamps etc.
function isLikelyRealPhone(p) {
  if (!p) return false;
  const s = String(p).trim();
  const digits = s.replace(/[^\d]/g, "");
  if (digits.length < 10) return false;
  if (s.startsWith("+20") && digits.length <= 12) return false; // your typical junk
  return true;
}

function isDEMobileE164(p) {
  if (!p) return false;
  const s = String(p).replace(/[^\d+]/g, "");
  // +49 15x/16x/17x are mobile ranges (rough but works)
  return /^\+49(15|16|17)\d{8,}$/.test(s);
}

