/**
 * n8n Code Node (JavaScript)
 * Name: Code | Build Subpage Candidates
 *
 * Erwartet pro Item mindestens eins von:
 * - base_url
 * - site
 * - source_site
 *
 * Output: mehrere Items pro Input (Fan-out)
 * - subpage_candidate (WAS du downstream offenbar erwartest)
 * - candidate_url (Alias, falls du es irgendwo schon nutzt)
 */

function normalizeBaseUrl(url) {
  if (!url || typeof url !== "string") return null;

  let u = url.trim();

  // Falls sowas wie "www.domain.de/" ohne scheme kommt
  if (!/^https?:\/\//i.test(u)) {
    u = "https://" + u;
  }

  // Entferne trailing slash
  u = u.replace(/\/+$/, "");

  return u;
}

function joinUrl(base, path) {
  const cleanBase = base.replace(/\/+$/, "");
  const cleanPath = path.startsWith("/") ? path : `/${path}`;
  return `${cleanBase}${cleanPath}`;
}

const CANDIDATE_PATHS = [
  "/kontakt",
  "/kontakt-und-informationen",
  "/contact",
  "/contact-us",
  "/get-in-touch",
  "/reach-us",
  "/impressum",
  "/imprint",
  "/legal",
  "/legal-notice",
  "/datenschutz",
  "/privacy",
];

const outputs = [];

for (const item of $input.all()) {
  const j = item.json || {};

  const baseRaw =
    j.base_url ||
    j.site ||
    j.source_site ||
    j.extracted_url ||
    j.source ||
    null;

  const baseUrl = normalizeBaseUrl(baseRaw);

  // Wenn keine gültige base URL, gib ein Item zurück, damit du es loggen kannst
  if (!baseUrl) {
    outputs.push({
      json: {
        ...j,
        has_valid_data: false,
        needs_fallback: true,
        jina_skip: true,
        jina_skip_reason: "no_valid_site_url",
        base_url: null,
        target_url: null,
        subpage_candidate: null,
        candidate_url: null,
      },
    });
    continue;
  }

  // Dedupe, falls du mehrfach gleiche Pfade hast
  const seen = new Set();

  for (const path of CANDIDATE_PATHS) {
    const candidate = joinUrl(baseUrl, path);

    if (seen.has(candidate)) continue;
    seen.add(candidate);

    outputs.push({
      json: {
        ...j,
        base_url: baseUrl,
        target_url: baseUrl,
        origin: baseUrl,
        is_internal_crawl_url: false,

        // DAS ist dein Missing Piece:
        subpage_candidate: candidate,

        // Alias (damit nichts anderes bricht):
        candidate_url: candidate,

        _jina_stage: "candidate",
        _url_source: "high_priority",
      },
    });
  }
}

return outputs;

// Node name: Pick Best Subpage Candidate
// Input: many items with fields like candidate_url, base_url, origin, site, etc.
// Output: exactly 1 item with subpage_candidate set to the best choice.

function normalizeUrl(u) {
  if (!u || typeof u !== "string") return null;
  u = u.trim();
  if (!u) return null;

  // Ensure protocol
  if (u.startsWith("//")) u = "https:" + u;

  // If it's a relative path, caller must join it elsewhere. We only accept absolute here.
  if (!u.startsWith("http://") && !u.startsWith("https://")) return null;

  // Remove trailing spaces
  return u;
}

function scoreUrl(u) {
  // Higher = better
  const url = u.toLowerCase();

  // Priority order: Impressum/legal notice > Datenschutz/privacy > Kontakt
  const rules = [
    { re: /\/impressum(\/|$)/, score: 1000, reason: "impressum" },
    { re: /\/imprint(\/|$)/, score: 950, reason: "imprint" },
    { re: /\/legal-notice(\/|$)/, score: 920, reason: "legal-notice" },
    { re: /\/legal(\/|$)/, score: 900, reason: "legal" },

    { re: /\/datenschutz(\/|$)/, score: 800, reason: "datenschutz" },
    { re: /\/privacy(\/|$)/, score: 780, reason: "privacy" },
    { re: /\/data-protection(\/|$)/, score: 760, reason: "data-protection" },

    { re: /\/kontakt(\/|$)/, score: 600, reason: "kontakt" },
    { re: /\/contact-us(\/|$)/, score: 580, reason: "contact-us" },
    { re: /\/contact(\/|$)/, score: 560, reason: "contact" },
    { re: /\/get-in-touch(\/|$)/, score: 540, reason: "get-in-touch" },
    { re: /\/reach-us(\/|$)/, score: 520, reason: "reach-us" },
  ];

  for (const r of rules) {
    if (r.re.test(url)) return { score: r.score, reason: r.reason };
  }

  // Penalize junk candidates
  if (url.includes("cookie")) return { score: 50, reason: "cookie" };
  if (url.includes("agb")) return { score: 80, reason: "agb" };

  // Default low score
  return { score: 100, reason: "default" };
}

const all = $input.all();

// Collect candidate URLs from common fields
const candidates = [];
for (const item of all) {
  const j = item.json || {};
  const raw =
    j.subpage_candidate ||
    j.candidate_url ||
    j.url ||
    null;

  const u = normalizeUrl(raw);
  if (!u) continue;

  const { score, reason } = scoreUrl(u);
  candidates.push({ u, score, reason, item });
}

if (candidates.length === 0) {
  // No candidates found, return one item with null candidate (keeps flow predictable)
  const first = all[0]?.json || {};
  return [
    {
      json: {
        ...first,
        subpage_candidate: null,
        subpage_candidate_reason: "no_candidates",
      },
    },
  ];
}

// Pick best by score, then shortest URL as tie-breaker
candidates.sort((a, b) => {
  if (b.score !== a.score) return b.score - a.score;
  return a.u.length - b.u.length;
});

const best = candidates[0];

// Output single item based on the original best item, but enforce the chosen candidate
return [
  {
    json: {
      ...(best.item.json || {}),
      subpage_candidate: best.u,
      subpage_candidate_reason: `${best.reason} (${best.score})`,
    },
  },
];

