function clean(s) {
  return (s || '').toString()
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, ' ')
    .replace(/&#64;|&commat;|&#x40;|%40/gi, '@')
    .replace(/&#46;|&period;|&#x2e;|%2e/gi, '.')
    .replace(/\(at\)|\[at\]|\{at\}/gi, '@')
    .replace(/\(dot\)|\[dot\]|\{dot\}/gi, '.')
    .replace(/mailto:\s*/gi, '');
}

function extractEmails(text) {
  const t = clean(text);
  const found = t.match(/[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}/gi) || [];
  const unique = [...new Set(found.map(e => e.toLowerCase()))];
  return unique.filter(e =>
    !e.includes('example.com') &&
    !e.includes('domain.com') &&
    !e.includes('sentry.io') &&
    !e.includes('wixpress.com') &&
    !e.endsWith('.png') &&
    !e.endsWith('.jpg') &&
    !e.endsWith('.gif') &&
    !e.endsWith('.webp') &&
    e.length < 60
  );
}

function extractPhones(text) {
  const t = clean(text);
  const found = t.match(/(\+?[0-9][\d\s()\-./]{7,}[0-9])/g) || [];
  return found
    .map(p => p.replace(/\s+/g, ' ').trim())
    .filter(p => {
      const digits = p.replace(/\D/g, '');
      return digits.length >= 10 && digits.length <= 16;
    });
}

function isMobile(phone) {
  const digits = phone.replace(/\D/g, '');
  return /^0?1[567]\d/.test(digits) || /^491[567]\d/.test(digits);
}

function toE164(phone) {
  let d = phone.replace(/\D/g, '');
  if (d.startsWith('49') && d.length >= 11 && d.length <= 15) return '+' + d;
  if (d.startsWith('0') && d.length >= 10 && d.length <= 14) return '+49' + d.slice(1);
  return null;
}

function isGermanNumber(e164) {
  return e164 !== null && e164.startsWith('+49');
}

function getHost(url) {
  try {
    let u = String(url || '').replace(/[\r\n\s]+/g, '');
    if (!/^https?:\/\//i.test(u)) u = 'https://' + u;
    return new URL(u).hostname.replace(/^www\./i, '').toLowerCase();
  } catch { return null; }
}

