let emails = extractEmails(allText);

if (baseHost && emails.length > 1) {
  const sameDomain = emails.filter(e => {
    const domain = e.split('@')[1];
    return domain && (domain === baseHost || domain.endsWith('.' + baseHost));
  });
  if (sameDomain.length > 0) emails = sameDomain;
}

const priorityPrefixes = ['info', 'kontakt', 'contact', 'office', 'hello', 'mail', 'support', 'team'];
let bestEmail = null;
for (const prefix of priorityPrefixes) {
  const found = emails.find(e => e.startsWith(prefix + '@'));
  if (found) { bestEmail = found; break; }
}
if (!bestEmail) bestEmail = emails[0] || null;

// ══════════ PHONES ══════════
const rawFromText = extractPhones(allText);
const rawFromPrev = [
  ...(originalContext.phones_e164 || []),
  ...(originalContext.phones || []),
  ...(originalContext.phones_raw || [])
];

const seenNorm = new Set();
const allE164 = [];

for (const raw of [...rawFromText, ...rawFromPrev]) {
  const e164 = toE164(raw);
  if (!e164 || !isGermanNumber(e164)) continue;
  const core = e164.slice(-10);
  if (seenNorm.has(core)) continue;
  seenNorm.add(core);
  allE164.push(e164);
}

const mobilePhones = allE164.filter(p => isMobile(p));
const landlinePhones = allE164.filter(p => !isMobile(p));

const primaryPhone = mobilePhones[0] || landlinePhones[0] || null;
const mobilePhone = mobilePhones[0] || null;

// ══════════ PATCH EXISTING OBJECTS ══════════

// Deep-clone um Original nicht zu verändern
const pdm = JSON.parse(JSON.stringify(originalContext.primary_decision_maker || {}));
const contacts = JSON.parse(JSON.stringify(originalContext.contacts || {}));

// ★ primary_decision_maker: Handy bevorzugt, Festnetz als Fallback
if (mobilePhone) {
  pdm.phone = mobilePhone;
  pdm.phone_type = 'mobile';
  // Quelle beibehalten wenn schon gesetzt, sonst aus Extraktion
  if (!pdm.phone_source_type) pdm.phone_source_type = 'extraction';
} else if (landlinePhones[0] && !pdm.phone) {
  pdm.phone = landlinePhones[0];
  pdm.phone_type = 'landline';
}

// Email patchen wenn gefunden und noch nicht vorhanden
if (bestEmail && !pdm.email) {
  pdm.email = bestEmail;
  pdm.email_source_type = 'extraction';
}

// ★ contacts: general_phone = Festnetz (Geschäftsnummer), mobile separat
if (landlinePhones[0]) {
  contacts.general_phone = landlinePhones[0];
  contacts.general_phone_type = 'landline';
}
if (mobilePhone) {
  contacts.mobile_phone = mobilePhone;
}
if (bestEmail && !contacts.general_email) {
  contacts.general_email = bestEmail;
  contacts.general_email_source_type = 'extraction';
}
contacts.other_emails = emails.filter(e => e !== bestEmail);

// ══════════ OUTPUT ══════════
return [{
  json: {
    ...originalContext,

    // ★ Gepatchte Objekte überschreiben die alten
    primary_decision_maker: pdm,
    contacts: contacts,

    _extraction_complete: true,
    base_url: baseUrl,
    base_host: baseHost,

    // Emails
    extracted_emails: emails,
    best_email: bestEmail,

    // Phones – alle E.164, Handy zuerst
    extracted_phones: [...mobilePhones, ...landlinePhones],
    mobile_phones: mobilePhones,
    landline_phones: landlinePhones,
    primary_phone: primaryPhone,
    mobile_phone: mobilePhone,

    // Überschreibe auch die alten phone-Felder
    phones: [...mobilePhones, ...landlinePhones],
    phones_e164: [...mobilePhones, ...landlinePhones],
    phone_primary: primaryPhone,

    has_mobile: mobilePhones.length > 0,
    whatsapp_possible: mobilePhones.length > 0,

    pages_processed: pagesCount,
    emails_found: emails.length,
    phones_found: allE164.length,
    mobile_phones_found: mobilePhones.length,

    _debug_text_length: allText.length,
    _debug_text_preview: allText.slice(0, 2000)
  }
}];

// Email Domain Sanity Check (FIXED + tolerant)
// Ziel:
// - Nimmt Website-Domain robust (website/original_url/source_site/domain)
// - Suspicious nur wenn: KEINE Email zur Website passt UND es NICHT klar "personal email allowed" ist
// - Markiert personal_email separat
// - export_to_instantly bleibt TRUE wenn wir wenigstens eine brauchbare Email haben

const j = { ...$json };

function safeStr(x) {
  return (typeof x === "string" ? x : "").trim();
}

function getHostFromUrl(url) {
  try {
    const u = new URL(url);
    return (u.hostname || "").toLowerCase();
  } catch (e) {
    return "";
  }
}

function getDomainFromEmail(email) {
  const e = safeStr(email).toLowerCase();
  const m = e.match(/@([a-z0-9.-]+\.[a-z]{2,})$/i);
  return m ? m[1].toLowerCase() : "";
}

// Heuristische Apex-Domain (ok für DE/COM/NET/ORG etc.)
function apexDomain(host) {
  const h = safeStr(host).toLowerCase().replace(/^www\./, "");
  if (!h) return "";

  const parts = h.split(".").filter(Boolean);
  if (parts.length <= 2) return h;

  const twoLevelTlds = new Set([
    "co.uk", "org.uk", "ac.uk",
    "com.au", "net.au", "org.au",
    "co.nz", "org.nz",
    "co.za",
    "com.br",
  ]);

  const last2 = parts.slice(-2).join(".");
  const last3 = parts.slice(-3).join(".");

  if (twoLevelTlds.has(last2) && parts.length >= 3) return last3;
  return last2;
}

// 1) Website-Domain robust bestimmen
const websiteUrl = safeStr(j.website || j.original_url || j.source_site || "");
const domainRaw = safeStr(j.domain || "");

// Priorität:
// - wenn domainRaw da ist: nimm das direkt
// - sonst aus URL host ziehen
const websiteHost = domainRaw
  ? domainRaw.toLowerCase().replace(/^www\./, "")
  : (websiteUrl ? getHostFromUrl(websiteUrl) : "");

const websiteApex = apexDomain(websiteHost);

// 2) Emails sammeln
const emailCandidates = []
  .concat(safeStr(j.best_email) ? [j.best_email] : [])
  .concat(safeStr(j.primary_email) ? [j.primary_email] : [])
  .concat(Array.isArray(j.emails) ? j.emails : [])
  .concat(Array.isArray(j.all_emails) ? j.all_emails : []);

const uniqueEmails = [...new Set(emailCandidates.map(e => safeStr(e)).filter(Boolean))];

// 3) Personal email domains (nicht blocken, nur markieren)
const personalDomains = new Set([
  "gmail.com", "googlemail.com",
  "yahoo.com", "yahoo.de",
  "outlook.com", "hotmail.com", "live.com",
  "icloud.com", "me.com",
  "aol.com", "gmx.de", "gmx.net", "web.de", "t-online.de",
]);

// 4) Optional: bekannte Müll-Domains blocken
const blockedEmailDomains = new Set([
  // z.B. 'ivof.com'
]);

let suspicious = false;
let reason = null;

let anyMatchesWebsite = false;
let anyBlocked = false;
let anyPersonal = false;

if (!uniqueEmails.length) {
  suspicious = true;
  reason = "missing_email";
} else {
  for (const em of uniqueEmails) {
    const ed = getDomainFromEmail(em);
    const edApex = apexDomain(ed);
    if (!edApex) continue;

    if (blockedEmailDomains.has(edApex)) {
      anyBlocked = true;
      continue;
    }

    if (personalDomains.has(edApex)) {
      anyPersonal = true;
      continue;
    }

    // wenn websiteApex fehlt, können wir match nicht prüfen
    if (websiteApex && edApex === websiteApex) {
      anyMatchesWebsite = true;
      break;
    }
  }

  // Logik:
  // - Wenn wir websiteApex haben und keine Email matched und keine Personal-only Situation -> suspicious
  // - Wenn websiteApex fehlt: NICHT automatisch suspicious, nur markieren
  if (!websiteApex) {
    suspicious = false;
    reason = "missing_website_domain_but_not_blocking";
  } else if (!anyMatchesWebsite) {
    // Wenn NUR personal emails existieren, ist das kein "scam", sondern "owner uses gmail/yahoo"
    const allArePersonalOrBlocked = uniqueEmails.every(em => {
      const ed = getDomainFromEmail(em);
      const edApex = apexDomain(ed);
      if (!edApex) return true;
      if (blockedEmailDomains.has(edApex)) return true;
      if (personalDomains.has(edApex)) return true;
      return false;
    });

    if (anyBlocked && !anyMatchesWebsite) {
      suspicious = true;
      reason = "blocked_email_domain";
    } else if (allArePersonalOrBlocked && anyPersonal) {
      // NICHT blocken, nur markieren
      suspicious = false;
      reason = `personal_email_only (website=${websiteApex})`;
    } else {
      suspicious = true;
      reason = `email_domain_mismatch (website=${websiteApex})`;
    }
  }
}

// 5) Output flags
j.website_domain_apex = websiteApex;
j.email_candidates = uniqueEmails;

j.has_personal_email = anyPersonal;
j.suspicious_email_domain = suspicious;

// Export-Rule:
// - export nur false, wenn suspicious=true ODER keine emails
j.export_to_instantly = !suspicious && uniqueEmails.length > 0;

// Optional: Wenn suspicious, kill die "best" emails
if (suspicious) {
  j.best_email = null;
  j.primary_email = null;
}

j.email_sanity_reason = reason;

return [{ json: j }];

// Source Sanity Check (Listing/Scam/Proxy Erkennung) - FIXED v3
// Ziel: Früh markieren, wenn "website/original_url" NICHT die echte Business-Website ist.
// v3 FIX: Zieht website + links/pages korrekt aus data[0] (Firecrawl/Outscraper style)

const root = { ...$json };

// --- helpers ---
function safeStr(x) { return (typeof x === 'string' ? x : '').trim(); }
function isHttpUrl(u) { return /^https?:\/\//i.test(u); }

function getHostFromUrl(url) {
  try {
    const u = new URL(url);
    return (u.hostname || '').toLowerCase();
  } catch { return ''; }
}

function apexDomain(host) {
  const h = safeStr(host).toLowerCase().replace(/^www\./, '');
  if (!h) return '';
  const parts = h.split('.').filter(Boolean);
  if (parts.length <= 2) return h;

  const twoLevelTlds = new Set([
    'co.uk','org.uk','ac.uk',
    'com.au','net.au','org.au',
    'co.nz','org.nz',
    'co.za',
    'com.br',
  ]);

  const last2 = parts.slice(-2).join('.');
  const last3 = parts.slice(-3).join('.');
  if (twoLevelTlds.has(last2) && parts.length >= 3) return last3;
  return last2;
}

function isAssetUrl(url) {
  const u = url.toLowerCase();
  return /\.(jpg|jpeg|png|webp|gif|svg|ico|css|js|mjs|map|pdf|mp4|mov|avi|mp3|wav|woff|woff2|ttf|eot)(\?|#|$)/i.test(u);
}

// --- unwrap nested source (Firecrawl/Outscraper pattern) ---
const first = Array.isArray(root.data) && root.data.length ? root.data[0] : null;
const meta = first?.metadata || root.metadata || {};

// --- website URL candidates (most important fix) ---
const websiteUrl =
  safeStr(root.website) ||
  safeStr(root.original_url) ||
  safeStr(root.source_site) ||
  safeStr(meta.url) ||               // ✅ your pinData: metadata.url
  safeStr(meta.ogUrl) ||
  safeStr(meta["og:url"]) ||
  safeStr(meta.sourceURL) ||         // sometimes http://domain
  '';

const websiteHost = websiteUrl ? getHostFromUrl(websiteUrl) : safeStr(root.domain || '');
const websiteApex = apexDomain(websiteHost);

// --- pages/links candidates (also important fix) ---
const pages =
  Array.isArray(root.pages) ? root.pages :
  Array.isArray(root._keep?.pages) ? root._keep.pages :
  Array.isArray(root.__keep?.pages) ? root.__keep.pages :
  Array.isArray(first?.pages) ? first.pages :
  [];

const rootLinks = Array.isArray(root.links) ? root.links : [];
const firstLinks = Array.isArray(first?.links) ? first.links : [];

const allCandidates = [
  ...pages.map(p => safeStr(p?.url)),
  ...rootLinks.map(u => safeStr(u)),
  ...firstLinks.map(u => safeStr(u)),   // ✅ your pinData: data[0].links
].filter(Boolean);

// --- ignore list ---
const ignoredApexHosts = new Set([
  'wixstatic.com',
  'wix.com',
  'wixsite.com',
  'cloudfront.net',
  'googleusercontent.com',
  'gstatic.com',
  'doubleclick.net',
  'googletagmanager.com',
  'google-analytics.com',
  'facebook.com',
  'instagram.com',
  'tiktok.com',
  'youtube.com',
  'linktr.ee',
]);

// --- listing/directory URL heuristics ---
const urlCombined = (websiteUrl + ' ' + safeStr(root.source_site) + ' ' + safeStr(root.original_url)).toLowerCase();
const looksLikeListingByUrl =
  /\/(salon|studio|anbieter|listing|verzeichnis|directory|business)\b/i.test(urlCombined) ||
  urlCombined.includes('verzeichnis') ||
  urlCombined.includes('branchenbuch') ||
  urlCombined.includes('anbieter') ||
  urlCombined.includes('listing') ||
  urlCombined.includes('directory');

// --- count ONLY real page urls ---
let pageApexCounts = {};
let pageCount = 0;
let ignoredCount = 0;

for (const rawUrl of allCandidates) {
  const u = safeStr(rawUrl);

  if (!isHttpUrl(u)) { ignoredCount++; continue; }
  if (isAssetUrl(u)) { ignoredCount++; continue; }

  const host = getHostFromUrl(u);
  if (!host) { ignoredCount++; continue; }

  const apex = apexDomain(host);
  if (!apex) { ignoredCount++; continue; }

  if (ignoredApexHosts.has(apex) || ignoredApexHosts.has(host)) { ignoredCount++; continue; }

  pageCount++;
  pageApexCounts[apex] = (pageApexCounts[apex] || 0) + 1;
}

// dominant pages apex
let dominantPageApex = null;
let dominantCount = 0;
for (const [k, v] of Object.entries(pageApexCounts)) {
  if (v > dominantCount) { dominantCount = v; dominantPageApex = k; }
}

const hasPages = pageCount > 0;

const pagesMostlyOtherDomain =
  hasPages &&
  websiteApex &&
  dominantPageApex &&
  dominantPageApex !== websiteApex &&
  (dominantCount / pageCount) >= 0.6;

// decision
let needsWebsiteDiscovery = false;
let sourceSanityReason = null;

if (!websiteApex) {
  needsWebsiteDiscovery = true;
  sourceSanityReason = 'missing_website_domain';
} else if (looksLikeListingByUrl && pagesMostlyOtherDomain) {
  needsWebsiteDiscovery = true;
  sourceSanityReason = `listing_url + pages_domain_mismatch (website=${websiteApex}, dominant_pages=${dominantPageApex})`;
} else if (pagesMostlyOtherDomain) {
  needsWebsiteDiscovery = true;
  sourceSanityReason = `pages_domain_mismatch (website=${websiteApex}, dominant_pages=${dominantPageApex})`;
}

// write outputs
root.website_url = websiteUrl;
root.website_domain_apex = websiteApex;
root.dominant_pages_apex = dominantPageApex;
root.pages_count = pageCount;
root.ignored_candidates_count = ignoredCount;

root.needs_website_discovery = needsWebsiteDiscovery;
root.source_sanity_reason = sourceSanityReason;

// if discovery needed: kill noisy capability signals
if (needsWebsiteDiscovery) {
  root.hat_online_buchung = false;
  root.booking_link_best = null;
  root.booking_provider = null;
  root.hat_kontaktformular = false;
  root.export_to_instantly = false;
}

return [{ json: root }];

// Normalize (FULL) - FIXED v2
// - Works even when Firecrawl webhook has data:[] and only metadata (Outscraper)
// - Uses metadata.site / site / source_site as URL
// - Uses metadata.phone / __keep.phone as phone source (so export_to_instantly can be true)
// - Keeps ALL original fields

const j = $json || {};

// --- helpers ---
function safeStr(x) { return (typeof x === 'string' ? x : '').trim(); }

function uniq(arr) {
  return Array.from(new Set((arr || []).filter(Boolean).map(v => String(v).trim())));
}

// E164-ish normalize (DE-friendly)
function normalizePhone(p) {
  let s = safeStr(p);
  if (!s) return '';
  s = s.replace(/[^0-9+]/g, '');
  if (s.startsWith('00')) s = '+' + s.slice(2);
  // if local DE like 015.. / 017.. etc, convert to +49
  if (s.startsWith('0') && !s.startsWith('+')) s = '+49' + s.slice(1);
  const digits = s.replace(/\D/g, '');
  if (digits.length < 8) return '';
  return s;
}

function getMeta(obj) {
  const m =
    (obj.body && obj.body.metadata && typeof obj.body.metadata === 'object' ? obj.body.metadata : null) ||
    (obj.metadata && typeof obj.metadata === 'object' ? obj.metadata : null) ||
    {};
  return m;
}

const meta = getMeta(j);
const keep = (j.__keep && typeof j.__keep === 'object') ? j.__keep : (j._keep && typeof j._keep === 'object' ? j._keep : {});

// ----------------------------
// 1) Flatten data[0] if present
// ----------------------------
const d0 =
  (Array.isArray(j.data) && j.data[0] && typeof j.data[0] === "object")
    ? j.data[0]
    : {};

// unified accessors (prefer root, fallback to data[0])
const html = String(j.html ?? d0.html ?? "");
const markdown = String(j.markdown ?? d0.markdown ?? "");
const text = String(j.text ?? d0.text ?? "");
const title = String(j.title ?? d0.title ?? "");

// links can appear at root or inside data[0]
const links = Array.isArray(j.links)
  ? j.links.map(String)
  : Array.isArray(d0.links)
    ? d0.links.map(String)
    : [];

// base url / extracted url (IMPORTANT: include meta.site)
const extracted_url = safeStr(
  j.extracted_url ??
  d0.extracted_url ??
  j.url ??
  d0.url ??
  j.site ??                 // ✅ Outscraper / your payload
  j.source_site ??          // ✅ your payload
  meta.site ??              // ✅ Outscraper in metadata
  meta.url ??               // fallback if present
  ""
);

// status code (normalize variants)
const statusCode = Number(j.statusCode ?? j.status ?? d0.statusCode ?? d0.status ?? 0);

// build a big searchable text
const haystack = [title, markdown, text, html, links.join("\n")].join("\n");

// ----------------------------
// 2) Extract emails
// ----------------------------
const emailRegex = /\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi;
let emails = (haystack.match(emailRegex) || [])
  .map(e => e.trim())
  .filter(Boolean);

// Also parse mailto:
for (const u of links) {
  const s = String(u);
  if (s.toLowerCase().startsWith("mailto:")) {
    const raw = s.split(":")[1] || "";
    const addr = raw.split("?")[0].trim();
    if (addr) emails.push(addr);
  }
}

// normalize emails (lowercase, dedupe)
emails = uniq(emails.map(e => e.toLowerCase()));

// ----------------------------
// 3) Extract phones
// ----------------------------
const phoneCandidates = [];

// tel: links
for (const u of links) {
  const s = String(u);
  if (s.toLowerCase().startsWith("tel:")) {
    let p = s.split(":")[1] || "";
    p = p.split("?")[0];
    phoneCandidates.push(p);
  }
}

// raw phone patterns in text/html (conservative)
const phoneRegex = /(?:\+?\d{1,3}[\s\-().]*)?(?:\d[\s\-().]*){7,15}\d/g;
phoneCandidates.push(...(haystack.match(phoneRegex) || []));

// ✅ Outscraper / metadata phones
if (meta.phone) phoneCandidates.push(meta.phone);
if (keep.phone) phoneCandidates.push(keep.phone);
if (j.phone) phoneCandidates.push(j.phone);

let phones = uniq(phoneCandidates.map(normalizePhone).filter(Boolean));

// mobile-ish heuristic (Germany)
const mobilePhones = phones.filter(p =>
  p.startsWith("+4915") || p.startsWith("+4916") || p.startsWith("+4917")
);

// ----------------------------
// 4) Flags
// ----------------------------
const hasEmail = emails.length > 0;
const hasPhone = phones.length > 0;
const hasContact = hasEmail || hasPhone;

// Export is allowed when we have contact info (even if crawl pages are empty)
const export_to_instantly = Boolean(hasContact);

// Website discovery only if we truly have no usable URL and no contact
const needs_website_discovery = !safeStr(extracted_url) && !hasContact;

// debug fields
const _debug = {
  extracted_url,
  statusCode,
  links_count: links.length,
  allText_length: haystack.length,
  emails_found: emails.length,
  phones_found: phones.length,
  mobile_phones_found: mobilePhones.length,
  export_to_instantly_type: typeof export_to_instantly,
  needs_website_discovery_type: typeof needs_website_discovery,
};

// ----------------------------
// 5) Return: keep EVERYTHING + ensure normalized fields exist
// ----------------------------
return {
  ...j,

  // keep sub-object
  _data0: d0,

  // normalized core fields
  extracted_url,
  statusCode,
  title,
  html,
  markdown,
  text,
  links,

  // extracted contacts
  emails,
  phones,
  mobile_phones: mobilePhones,
  has_email: hasEmail,
  has_phone: hasPhone,
  has_contact: hasContact,

  // routing flags
  export_to_instantly,
  needs_website_discovery,

  // debug
  _debug,
};

// Scrape Status Mapper v1
// Ziel: aus raw_text / data / html/text eine saubere Status-Klassifikation bauen,
// die du in Excel mappen kannst (scrape_status).
// Erkannt: CAPTCHA/Cloudflare, HTTP-Codes, Timeout, DNS, Connection refused, SSL, 404, 5xx, "site down".

const j = $json ?? {};

function safeStr(x) { return (typeof x === 'string' ? x : '').trim(); }

// Sammle möglichen Rohtext aus allen üblichen Feldern
const rawText =
  safeStr(j._firecrawl_data?.raw_text) ||
  safeStr(j.data) ||
  safeStr(j.text) ||
  safeStr(j.markdown) ||
  safeStr(j.html) ||
  safeStr(j.raw?.body?.data) ||
  safeStr(j.raw?.body?.text) ||
  '';

// HTTP Status Code aus Feldern ODER aus Text extrahieren
function detectHttpStatus(obj, text) {
  const direct =
    Number(obj.http_status ?? obj.statusCode ?? obj.status ?? obj.response_status ?? 0) ||
    Number(obj._firecrawl_data?.http_status ?? 0) ||
    0;

  if (direct) return direct;

  // Beispiele: "error 403", "403: Forbidden", "HTTP/2 401"
  const m =
    text.match(/\bHTTP\/\d(?:\.\d)?\s+(\d{3})\b/i) ||
    text.match(/\berror\s+(\d{3})\b/i) ||
    text.match(/\b(\d{3})\s*:\s*(forbidden|unauthorized|not found|too many requests|service unavailable|bad gateway|gateway timeout)\b/i) ||
    null;

  return m ? Number(m[1]) : 0;
}

const httpStatus = detectHttpStatus(j, rawText);
const t = rawText.toLowerCase();

// Erkennung von Blockern / CAPTCHA / WAF
const hasCaptcha =
  t.includes('captcha') ||
  t.includes('security verification') ||
  t.includes('verify you are not a bot') ||
  t.includes('just a moment') ||
  t.includes('checking your browser') ||
  t.includes('cf-ray') ||
  t.includes('cloudflare') ||
  t.includes('ddos');

const blockedBy =
  t.includes('cloudflare') || t.includes('cf-ray') || t.includes('just a moment') || t.includes('checking your browser')
    ? 'cloudflare'
    : hasCaptcha
      ? 'captcha_or_waf'
      : null;

// Netzwerk-/Erreichbarkeitsfehler
const isTimeout =
  t.includes('timeout') ||
  t.includes('timed out') ||
  t.includes('etimedout') ||
  t.includes('request timed out');

const isDns =
  t.includes('enotfound') ||
  t.includes('dns') && t.includes('failed') ||
  t.includes('name or service not known') ||
  t.includes('getaddrinfo');

const isConnRefused =
  t.includes('econnrefused') ||
  t.includes('connection refused');

const isSsl =
  t.includes('ssl') && (t.includes('error') || t.includes('handshake')) ||
  t.includes('certificate') ||
  t.includes('cert') && t.includes('invalid');

// Inhalts-Qualität (nur wenn du willst, optional)
const hasRealContent = rawText.length >= 400 && !hasCaptcha;

// Haupt-Klassifikation
let scrape_status = 'unknown';
let scrape_reason = 'Unbekannter Fehler / kein eindeutiges Pattern erkannt.';

// 1) CAPTCHA / Block
if (hasCaptcha && (httpStatus === 403 || httpStatus === 401 || httpStatus === 429 || httpStatus === 0)) {
  scrape_status = httpStatus ? `captcha_${httpStatus}` : 'captcha';
  scrape_reason = 'Zugriff blockiert (CAPTCHA/WAF/Sicherheitsprüfung).';
}
// 2) Rate Limit
else if (httpStatus === 429) {
  scrape_status = 'rate_limited_429';
  scrape_reason = 'Rate Limit (429 Too Many Requests).';
}
// 3) Auth/Forbidden
else if (httpStatus === 401) {
  scrape_status = 'unauthorized_401';
  scrape_reason = 'Unauthorized (401). Zugriff erfordert Auth.';
}
else if (httpStatus === 403) {
  scrape_status = 'forbidden_403';
  scrape_reason = 'Forbidden (403). Zugriff blockiert oder WAF.';
}
// 4) Not Found
else if (httpStatus === 404) {
  scrape_status = 'not_found_404';
  scrape_reason = 'Seite nicht gefunden (404).';
}
// 5) Server Fehler
else if (httpStatus >= 500 && httpStatus <= 599) {
  scrape_status = `server_error_${httpStatus}`;
  scrape_reason = `Serverfehler (${httpStatus}).`;
}
// 6) Timeout / DNS / Connection / SSL
else if (isTimeout) {
  scrape_status = 'timeout';
  scrape_reason = 'Timeout beim Abruf (Zeitüberschreitung).';
}
else if (isDns) {
  scrape_status = 'dns_error';
  scrape_reason = 'DNS Fehler (Domain nicht auflösbar).';
}
else if (isConnRefused) {
  scrape_status = 'connection_refused';
  scrape_reason = 'Verbindung abgelehnt (Server/Port verweigert).';
}
else if (isSsl) {
  scrape_status = 'ssl_error';
  scrape_reason = 'SSL/Zertifikatsfehler.';
}
// 7) OK-ish Content
else if (hasRealContent && (httpStatus === 200 || httpStatus === 0)) {
  scrape_status = 'ok_content';
  scrape_reason = 'Inhalt vorhanden, Scrape grundsätzlich erfolgreich.';
}
// 8) Generisch: HTTP Code vorhanden
else if (httpStatus) {
  scrape_status = `http_${httpStatus}`;
  scrape_reason = `HTTP Status ${httpStatus}.`;
}

// Debug excerpt (Excel-tauglich kurz)
const scrape_raw_excerpt = rawText
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 240);

return [{
  json: {
    ...j,
    scrape_http_status: httpStatus || null,
    scrape_blocked_by: blockedBy,
    scrape_status,
    scrape_reason,
    scrape_raw_excerpt,
  }
}];

// Scrape Status Mapper v1
// Ziel: aus raw_text / data / html/text eine saubere Status-Klassifikation bauen,
// die du in Excel mappen kannst (scrape_status).
// Erkannt: CAPTCHA/Cloudflare, HTTP-Codes, Timeout, DNS, Connection refused, SSL, 404, 5xx, "site down".

const j = $json ?? {};

function safeStr(x) { return (typeof x === 'string' ? x : '').trim(); }

// Sammle möglichen Rohtext aus allen üblichen Feldern
const rawText =
  safeStr(j._firecrawl_data?.raw_text) ||
  safeStr(j.data) ||
  safeStr(j.text) ||
  safeStr(j.markdown) ||
  safeStr(j.html) ||
  safeStr(j.raw?.body?.data) ||
  safeStr(j.raw?.body?.text) ||
  '';

// HTTP Status Code aus Feldern ODER aus Text extrahieren
function detectHttpStatus(obj, text) {
  const direct =
    Number(obj.http_status ?? obj.statusCode ?? obj.status ?? obj.response_status ?? 0) ||
    Number(obj._firecrawl_data?.http_status ?? 0) ||
    0;

  if (direct) return direct;

  // Beispiele: "error 403", "403: Forbidden", "HTTP/2 401"
  const m =
    text.match(/\bHTTP\/\d(?:\.\d)?\s+(\d{3})\b/i) ||
    text.match(/\berror\s+(\d{3})\b/i) ||
    text.match(/\b(\d{3})\s*:\s*(forbidden|unauthorized|not found|too many requests|service unavailable|bad gateway|gateway timeout)\b/i) ||
    null;

  return m ? Number(m[1]) : 0;
}

const httpStatus = detectHttpStatus(j, rawText);
const t = rawText.toLowerCase();

// Erkennung von Blockern / CAPTCHA / WAF
const hasCaptcha =
  t.includes('captcha') ||
  t.includes('security verification') ||
  t.includes('verify you are not a bot') ||
  t.includes('just a moment') ||
  t.includes('checking your browser') ||
  t.includes('cf-ray') ||
  t.includes('cloudflare') ||
  t.includes('ddos');

const blockedBy =
  t.includes('cloudflare') || t.includes('cf-ray') || t.includes('just a moment') || t.includes('checking your browser')
    ? 'cloudflare'
    : hasCaptcha
      ? 'captcha_or_waf'
      : null;

// Netzwerk-/Erreichbarkeitsfehler
const isTimeout =
  t.includes('timeout') ||
  t.includes('timed out') ||
  t.includes('etimedout') ||
  t.includes('request timed out');

const isDns =
  t.includes('enotfound') ||
  t.includes('dns') && t.includes('failed') ||
  t.includes('name or service not known') ||
  t.includes('getaddrinfo');

const isConnRefused =
  t.includes('econnrefused') ||
  t.includes('connection refused');

const isSsl =
  t.includes('ssl') && (t.includes('error') || t.includes('handshake')) ||
  t.includes('certificate') ||
  t.includes('cert') && t.includes('invalid');

// Inhalts-Qualität (nur wenn du willst, optional)
const hasRealContent = rawText.length >= 400 && !hasCaptcha;

// Haupt-Klassifikation
let scrape_status = 'unknown';
let scrape_reason = 'Unbekannter Fehler / kein eindeutiges Pattern erkannt.';

// 1) CAPTCHA / Block
if (hasCaptcha && (httpStatus === 403 || httpStatus === 401 || httpStatus === 429 || httpStatus === 0)) {
  scrape_status = httpStatus ? `captcha_${httpStatus}` : 'captcha';
  scrape_reason = 'Zugriff blockiert (CAPTCHA/WAF/Sicherheitsprüfung).';
}
// 2) Rate Limit
else if (httpStatus === 429) {
  scrape_status = 'rate_limited_429';
  scrape_reason = 'Rate Limit (429 Too Many Requests).';
}
// 3) Auth/Forbidden
else if (httpStatus === 401) {
  scrape_status = 'unauthorized_401';
  scrape_reason = 'Unauthorized (401). Zugriff erfordert Auth.';
}
else if (httpStatus === 403) {
  scrape_status = 'forbidden_403';
  scrape_reason = 'Forbidden (403). Zugriff blockiert oder WAF.';
}
// 4) Not Found
else if (httpStatus === 404) {
  scrape_status = 'not_found_404';
  scrape_reason = 'Seite nicht gefunden (404).';
}
// 5) Server Fehler
else if (httpStatus >= 500 && httpStatus <= 599) {
  scrape_status = `server_error_${httpStatus}`;
  scrape_reason = `Serverfehler (${httpStatus}).`;
}
// 6) Timeout / DNS / Connection / SSL
else if (isTimeout) {
  scrape_status = 'timeout';
  scrape_reason = 'Timeout beim Abruf (Zeitüberschreitung).';
}
else if (isDns) {
  scrape_status = 'dns_error';
  scrape_reason = 'DNS Fehler (Domain nicht auflösbar).';
}
else if (isConnRefused) {
  scrape_status = 'connection_refused';
  scrape_reason = 'Verbindung abgelehnt (Server/Port verweigert).';
}
else if (isSsl) {
  scrape_status = 'ssl_error';
  scrape_reason = 'SSL/Zertifikatsfehler.';
}
// 7) OK-ish Content
else if (hasRealContent && (httpStatus === 200 || httpStatus === 0)) {
  scrape_status = 'ok_content';
  scrape_reason = 'Inhalt vorhanden, Scrape grundsätzlich erfolgreich.';
}
// 8) Generisch: HTTP Code vorhanden
else if (httpStatus) {
  scrape_status = `http_${httpStatus}`;
  scrape_reason = `HTTP Status ${httpStatus}.`;
}

// Debug excerpt (Excel-tauglich kurz)
const scrape_raw_excerpt = rawText
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 240);

return [{
  json: {
    ...j,
    scrape_http_status: httpStatus || null,
    scrape_blocked_by: blockedBy,
    scrape_status,
    scrape_reason,
    scrape_raw_excerpt,
  }
}];

/**
 * Decide Next Candidate (max 2 Versuche)
 * 
 * Holt gespeicherten Kontext aus StaticData (weil HTTP Request
 * alle Input-Felder überschreibt), merged mit API-Response,
 * entscheidet ob fertig oder nächster Kandidat.
 */

const staticData = $getWorkflowStaticData('global');

// ── 1) Kontext wiederherstellen + API-Response mergen ──
const ctx = JSON.parse(staticData._amfContext || '{}');
const apiResponse = $json;                       // von HTTP Request2
const j = { ...ctx, amf_verify: apiResponse };   // alles zusammen

function toStr(v) {
  return v === null || v === undefined ? "" : String(v).trim();
}

const candidates = Array.isArray(j.email_candidates) ? j.email_candidates : [];
let idx = Number.isFinite(j.email_candidate_index) ? j.email_candidate_index : 0;

let tries = Number.isFinite(j.tries) ? j.tries : 0;
tries += 1;

const status = toStr(
  j.amf_verify?.email_status || j.amf_verify?.status || ""
).toLowerCase();

// ── 2) Akzeptable Status ──
const ACCEPT = new Set(["valid", "risky"]);

if (ACCEPT.has(status)) {
  // ✅ Treffer – diese Email ist gut
  j.email_done      = true;
  j.email_exhausted = false;
  j.chosen_email    = toStr(j.email_to_verify);
  j.best_email      = j.chosen_email;
  j.primary_email   = j.chosen_email;
  j.tries           = tries;

  delete staticData._amfContext;   // aufräumen
  return j;
}

// ── 3) Nicht akzeptiert – noch Versuche übrig? ──
const MAX_TRIES = 2;

if (tries >= MAX_TRIES || !candidates[idx + 1]) {
  // ❌ Alle Versuche aufgebraucht oder keine Kandidaten mehr
  j.email_done      = true;
  j.email_exhausted = true;
  j.chosen_email    = null;
  j.best_email      = null;
  j.tries           = tries;

  delete staticData._amfContext;
  return j;
}

// ── 4) Nächsten Kandidaten vorbereiten ──
const nextIdx = idx + 1;
j.email_candidate_index = nextIdx;
j.email_to_verify       = candidates[nextIdx];
j.amf                   = j.amf || {};
j.amf.email             = candidates[nextIdx];
j.email_done            = false;
j.email_exhausted       = false;
j.tries                 = tries;

// Kontext mit neuem Index speichern für nächste Runde
staticData._amfContext = JSON.stringify(j);

return j;
